@import url("https://fonts.googleapis.com/css2?family=Figtree:wght@400;600;700&display=swap");
*, *::before, *::after {
  box-sizing: border-box;
}

#searchBox {
  font-family: "Figtree", sans-serif;
  padding: 0;
}

.card {
  background: #fff;
  border: 0.5px solid rgba(0, 0, 0, 0.1);
  border-radius: 10px;
  overflow: hidden;
}

.widget-header {
  display: flex;
  align-items: center;
  gap: 8px;
  padding: 14px 16px;
  border-bottom: 0.5px solid rgba(0, 0, 0, 0.08);
}

.widget-header-icon {
  width: 26px;
  height: 26px;
  border-radius: 8px;
  background: rgba(5, 4, 46, 0.1);
  display: flex;
  align-items: center;
  justify-content: center;
  color: #05042E;
  font-size: 13px;
  flex-shrink: 0;
}

.widget-header span {
  font-size: 10px;
  font-weight: 700;
  color: #05042E;
  text-transform: uppercase;
  letter-spacing: 0.05em;
}

#assetSearchInput {
  width: 100%;
  box-sizing: border-box;
  padding: 10px 16px;
  font-family: "Figtree", sans-serif;
  font-size: 13px;
  font-weight: 600;
  color: #05042E;
  border: none;
  border-bottom: 0.5px solid rgba(0, 0, 0, 0.08);
  outline: none;
  background: #fff;
}

#assetSearchInput::placeholder {
  color: #b0aeb8;
  font-weight: 400;
}

#assetSearchInput:focus {
  box-shadow: inset 0 -2px 0 #469BC0;
}

#searchResult {
  padding: 0;
}

.result-card {
  margin: 14px;
  background: rgba(5, 4, 46, 0.04);
  border: 0.5px solid rgba(0, 0, 0, 0.06);
  border-radius: 8px;
  padding: 14px 16px;
}

.result-row {
  display: flex;
  justify-content: space-between;
  align-items: center;
  padding: 8px 0;
  border-bottom: 0.5px solid rgba(0, 0, 0, 0.06);
  font-size: 13px;
  font-weight: 600;
  color: #05042E;
}

.result-row:last-of-type {
  border-bottom: none;
}

.result-row .label {
  color: #888780;
  font-weight: 700;
  font-size: 10px;
  text-transform: uppercase;
  letter-spacing: 0.05em;
}

#addToSaleBtn {
  width: 100%;
  margin-top: 12px;
  padding: 9px;
  font-family: "Figtree", sans-serif;
  background: #A3E851;
  color: #05042E;
  font-weight: 700;
  font-size: 12px;
  border: none;
  border-radius: 6px;
  cursor: pointer;
  transition: background 0.15s;
}

#addToSaleBtn:hover {
  background: #5DC987;
}

#addToSaleBtn:disabled {
  background: #E0DFE1;
  color: #aaa;
  cursor: not-allowed;
}

.no-result {
  margin: 14px;
  color: #888780;
  font-size: 12px;
  font-weight: 600;
  text-align: center;
  padding: 24px 0;
}

.status-badge {
  display: inline-block;
  padding: 3px 10px;
  border-radius: 20px;
  font-weight: 700;
  font-size: 10px;
  text-transform: uppercase;
  letter-spacing: 0.05em;
}

.status-intake {
  background: #E0DFE1;
  color: #475569;
}

.status-data {
  background: #EDE9FE;
  color: #5B21B6;
}

.status-compliance {
  background: #FAEEDA;
  color: #633806;
}

.status-evaluation {
  background: #E6F1FB;
  color: #0C447C;
}

.status-sales {
  background: #E1F5EE;
  color: #085041;
}

.status-end_of_life {
  background: #E0DFE1;
  color: #374151;
}

.status-asset {
  background: #CCFBF1;
  color: #0F6E56;
}

.status-default {
  background: rgba(5, 4, 46, 0.06);
  color: #888780;
}

